all_icons = [LAYDOWN11,LAYDOWN12,LAYDOWN13,LAYDOWN14,LAYDOWN15,LAYDOWN16,LAYDOWN17,LAYDOWN18]

lcd = OledBoot()
# Initialize screen
lcd.fill(0)
lcd.show()

def lay_down( lcd, x, y ):
    global all_icons
    for icon in all_icons:
        lcd.fill(0) # Clear
        # Draw first image
        draw_icon( lcd, icon,x,y,1 )
        lcd.show()
        time.sleep_ms( 250 )

def lay_up( lcd, x, y ):
    global all_icons
    for icon in all_icons[::-1]:
        lcd.fill(0) # Clear
        # Draw first image
        draw_icon( lcd, icon,x,y,1 )
        lcd.show()
        time.sleep_ms( 250 )


while True:
	x,y = 35, 15
	lay_down( lcd, x, y )
	time.sleep( 2 )
	
	lay_up( lcd, x, y )
	time.sleep( 2 )
